openscad:
$fn = 60;
case_dia = 42; // [30:1:80]
case_thick = 9; // [6:1:15]
dial_dia = 36; // [20:1:70]
bezel_h = 2; // [1:0.5:4]
hand_thick = 1.2; // [0.8:0.2:2]
date_w = 6; // [4:0.5:10]
date_h = 4; // [3:0.5:8]
hour_len = 9; // [5:0.5:18]
min_len = 13; // [7:0.5:22]
sec_len = 15; // [8:0.5:24]
module watch() {
  color([0.9,0.95,1,0.35])
  difference() {
    cylinder(d=case_dia,h=case_thick);
    translate([0,0,case_thick-bezel_h])
      cylinder(d=case_dia-3,h=bezel_h+0.1);
  }
  color([0.15,0.15,0.15])
  translate([0,0,case_thick-3])
    cylinder(d=dial_dia,h=2.5);
  color([1,1,1])
  translate([dial_dia/2.8,0,case_thick-1.6])
    cube([date_w,date_h,0.8],center=true);
  color([1,1,1])
  translate([0,0,case_thick-0.8]) {
    rotate([0,0,150])
      cube([hand_thick,hour_len,1.5],center=true);
    rotate([0,0,30])
      cube([hand_thick*0.8,min_len,1.5],center=true);
    rotate([0,0,240])
      cube([hand_thick*0.4,sec_len,1.5],center=true);
  }
  color([0.2,0.2,0.2])
  translate([0,0,case_thick-0.3])
    cylinder(d=3,h=2);
}
watch();
